/**
 * Order Module Events
 *
 * Event definitions and emitters for the Order module.
 * Provides typed domain events for order, table, zone, QR code,
 * customer, service request, and feedback operations.
 *
 * @module modules/order/order.events
 *
 * @example
 * ```typescript
 * import { OrderModuleEvents, emitOrderCreated } from '@/modules/order/order.events';
 *
 * // Emit an order created event
 * await emitOrderCreated(eventService, {
 *   orderId: 'ord_123',
 *   orderNumber: 'ORD-20260201-001',
 *   organizationId: 'org_456',
 *   type: 'DINE_IN',
 *   totalAmount: 250.00,
 *   tableId: 'table_789',
 * });
 * ```
 */

import type { EventService } from '@/core/services/event.service';
import type {
  OrderStatus,
  OrderType,
  TableStatus,
  OrderItemStatus,
  ServiceRequestType,
} from '@/modules/order/order.types';

// -----------------------------------------------------------------------------
// Base Event Types
// -----------------------------------------------------------------------------

/**
 * Base event payload with common fields
 */
export interface BaseEventPayload {
  /** Organization ID */
  organizationId: string;
  /** Event timestamp */
  timestamp: string;
  /** User who triggered the event */
  triggeredBy?: string;
}

// -----------------------------------------------------------------------------
// Order Event Types
// -----------------------------------------------------------------------------

/**
 * Order created event payload
 */
export interface OrderCreatedEventPayload extends BaseEventPayload {
  /** Order ID */
  orderId: string;
  /** Order number */
  orderNumber: string;
  /** Order type */
  type: OrderType;
  /** Total amount */
  totalAmount: number;
  /** Table ID (if dine-in) */
  tableId: string | null;
  /** Customer ID (if registered) */
  customerId: string | null;
  /** Item count */
  itemCount: number;
}

/**
 * Order updated event payload
 */
export interface OrderUpdatedEventPayload extends BaseEventPayload {
  /** Order ID */
  orderId: string;
  /** Order number */
  orderNumber: string;
  /** Changed fields */
  changes: Record<string, unknown>;
  /** Updated by user ID */
  updatedBy?: string;
}

/**
 * Order status changed event payload
 */
export interface OrderStatusChangedEventPayload extends BaseEventPayload {
  /** Order ID */
  orderId: string;
  /** Order number */
  orderNumber: string;
  /** Previous status */
  previousStatus: OrderStatus;
  /** New status */
  newStatus: OrderStatus;
  /** Cancel reason (if cancelled) */
  cancelReason: string | null;
  /** Changed by user ID */
  changedBy?: string;
}

/**
 * Order confirmed event payload
 */
export interface OrderConfirmedEventPayload extends BaseEventPayload {
  /** Order ID */
  orderId: string;
  /** Order number */
  orderNumber: string;
  /** Confirmed at timestamp */
  confirmedAt: string;
  /** Confirmed by user ID */
  confirmedBy?: string;
}

/**
 * Order preparing event payload
 */
export interface OrderPreparingEventPayload extends BaseEventPayload {
  /** Order ID */
  orderId: string;
  /** Order number */
  orderNumber: string;
  /** Started at timestamp */
  startedAt: string;
}

/**
 * Order ready event payload
 */
export interface OrderReadyEventPayload extends BaseEventPayload {
  /** Order ID */
  orderId: string;
  /** Order number */
  orderNumber: string;
  /** Ready at timestamp */
  readyAt: string;
  /** Preparation time in minutes */
  prepTimeMinutes: number;
}

/**
 * Order delivered event payload
 */
export interface OrderDeliveredEventPayload extends BaseEventPayload {
  /** Order ID */
  orderId: string;
  /** Order number */
  orderNumber: string;
  /** Delivered at timestamp */
  deliveredAt: string;
  /** Delivered by user ID */
  deliveredBy?: string;
}

/**
 * Order completed event payload
 */
export interface OrderCompletedEventPayload extends BaseEventPayload {
  /** Order ID */
  orderId: string;
  /** Order number */
  orderNumber: string;
  /** Completed at timestamp */
  completedAt: string;
  /** Total amount */
  totalAmount: number;
  /** Order duration in minutes */
  durationMinutes: number;
}

/**
 * Order cancelled event payload
 */
export interface OrderCancelledEventPayload extends BaseEventPayload {
  /** Order ID */
  orderId: string;
  /** Order number */
  orderNumber: string;
  /** Cancelled at timestamp */
  cancelledAt: string;
  /** Cancellation reason */
  reason: string;
  /** Previous status before cancellation */
  previousStatus: OrderStatus;
  /** Cancelled by user ID */
  cancelledBy?: string;
}

// -----------------------------------------------------------------------------
// Order Item Event Types
// -----------------------------------------------------------------------------

/**
 * Order item added event payload
 */
export interface OrderItemAddedEventPayload extends BaseEventPayload {
  /** Order ID */
  orderId: string;
  /** Order number */
  orderNumber: string;
  /** Item ID */
  itemId: string;
  /** Product ID */
  productId: string;
  /** Product name */
  productName: string;
  /** Quantity */
  quantity: number;
  /** Added by user ID */
  addedBy?: string;
}

/**
 * Order item updated event payload
 */
export interface OrderItemUpdatedEventPayload extends BaseEventPayload {
  /** Order ID */
  orderId: string;
  /** Order number */
  orderNumber: string;
  /** Item ID */
  itemId: string;
  /** Changed fields */
  changes: Record<string, unknown>;
  /** Updated by user ID */
  updatedBy?: string;
}

/**
 * Order item removed event payload
 */
export interface OrderItemRemovedEventPayload extends BaseEventPayload {
  /** Order ID */
  orderId: string;
  /** Order number */
  orderNumber: string;
  /** Item ID */
  itemId: string;
  /** Product name (for logging) */
  productName: string;
  /** Removed by user ID */
  removedBy?: string;
}

/**
 * Order item status changed event payload
 */
export interface OrderItemStatusChangedEventPayload extends BaseEventPayload {
  /** Order ID */
  orderId: string;
  /** Order number */
  orderNumber: string;
  /** Item ID */
  itemId: string;
  /** Previous status */
  previousStatus: OrderItemStatus;
  /** New status */
  newStatus: OrderItemStatus;
  /** Changed by user ID */
  changedBy?: string;
}

// -----------------------------------------------------------------------------
// Table Event Types
// -----------------------------------------------------------------------------

/**
 * Table created event payload
 */
export interface TableCreatedEventPayload extends BaseEventPayload {
  /** Table ID */
  tableId: string;
  /** Table number */
  tableNumber: string;
  /** Zone ID */
  zoneId: string | null;
  /** Capacity */
  capacity: number;
  /** Created by user ID */
  createdBy?: string;
}

/**
 * Table updated event payload
 */
export interface TableUpdatedEventPayload extends BaseEventPayload {
  /** Table ID */
  tableId: string;
  /** Table number */
  tableNumber: string;
  /** Changed fields */
  changes: Record<string, unknown>;
  /** Updated by user ID */
  updatedBy?: string;
}

/**
 * Table deleted event payload
 */
export interface TableDeletedEventPayload extends BaseEventPayload {
  /** Table ID */
  tableId: string;
  /** Table number */
  tableNumber: string;
  /** Deleted by user ID */
  deletedBy?: string;
}

/**
 * Table status changed event payload
 */
export interface TableStatusChangedEventPayload extends BaseEventPayload {
  /** Table ID */
  tableId: string;
  /** Table number */
  tableNumber: string;
  /** Previous status */
  previousStatus: TableStatus;
  /** New status */
  newStatus: TableStatus;
  /** Associated order ID (if occupied) */
  orderId: string | null;
  /** Changed by user ID */
  changedBy?: string;
}

// -----------------------------------------------------------------------------
// Zone Event Types
// -----------------------------------------------------------------------------

/**
 * Zone created event payload
 */
export interface ZoneCreatedEventPayload extends BaseEventPayload {
  /** Zone ID */
  zoneId: string;
  /** Zone name */
  name: string;
  /** Zone color */
  color: string | null;
  /** Created by user ID */
  createdBy?: string;
}

/**
 * Zone updated event payload
 */
export interface ZoneUpdatedEventPayload extends BaseEventPayload {
  /** Zone ID */
  zoneId: string;
  /** Zone name */
  name: string;
  /** Changed fields */
  changes: Record<string, unknown>;
  /** Updated by user ID */
  updatedBy?: string;
}

/**
 * Zone deleted event payload
 */
export interface ZoneDeletedEventPayload extends BaseEventPayload {
  /** Zone ID */
  zoneId: string;
  /** Zone name */
  name: string;
  /** Deleted by user ID */
  deletedBy?: string;
}

// -----------------------------------------------------------------------------
// QR Code Event Types
// -----------------------------------------------------------------------------

/**
 * QR code created event payload
 */
export interface QRCodeCreatedEventPayload extends BaseEventPayload {
  /** QR Code ID */
  qrCodeId: string;
  /** Unique code */
  code: string;
  /** Menu ID */
  menuId: string;
  /** Table ID (if table QR) */
  tableId: string | null;
  /** QR code type */
  type: string;
  /** Created by user ID */
  createdBy?: string;
}

/**
 * QR code scanned event payload
 */
export interface QRCodeScannedEventPayload extends BaseEventPayload {
  /** QR Code ID */
  qrCodeId: string;
  /** Unique code */
  code: string;
  /** Menu ID */
  menuId: string;
  /** Table ID (if table QR) */
  tableId: string | null;
  /** Scan metadata */
  scanData: {
    /** User agent */
    userAgent: string | null;
    /** Device type */
    deviceType: string | null;
    /** Browser */
    browser: string | null;
    /** Operating system */
    os: string | null;
    /** Country */
    country: string | null;
    /** City */
    city: string | null;
  };
}

/**
 * QR code deleted event payload
 */
export interface QRCodeDeletedEventPayload extends BaseEventPayload {
  /** QR Code ID */
  qrCodeId: string;
  /** Unique code */
  code: string;
  /** Deleted by user ID */
  deletedBy?: string;
}

// -----------------------------------------------------------------------------
// Customer Event Types
// -----------------------------------------------------------------------------

/**
 * Customer created event payload
 */
export interface CustomerCreatedEventPayload extends BaseEventPayload {
  /** Customer ID */
  customerId: string;
  /** Email */
  email: string | null;
  /** Phone */
  phone: string | null;
  /** Full name */
  fullName: string | null;
}

/**
 * Customer updated event payload
 */
export interface CustomerUpdatedEventPayload extends BaseEventPayload {
  /** Customer ID */
  customerId: string;
  /** Changed fields */
  changes: Record<string, unknown>;
  /** Updated by user ID */
  updatedBy?: string;
}

// -----------------------------------------------------------------------------
// Service Request Event Types
// -----------------------------------------------------------------------------

/**
 * Service requested event payload
 */
export interface ServiceRequestedEventPayload extends BaseEventPayload {
  /** Request ID */
  requestId: string;
  /** Table ID */
  tableId: string;
  /** Table number */
  tableNumber: string;
  /** Request type */
  type: ServiceRequestType;
  /** Custom message */
  message: string | null;
}

/**
 * Service resolved event payload
 */
export interface ServiceResolvedEventPayload extends BaseEventPayload {
  /** Request ID */
  requestId: string;
  /** Table ID */
  tableId: string;
  /** Table number */
  tableNumber: string;
  /** Request type */
  type: string;
  /** Resolved at timestamp */
  resolvedAt: string;
  /** Wait time in minutes */
  waitTimeMinutes: number;
  /** Resolved by user ID */
  resolvedBy?: string;
}

// -----------------------------------------------------------------------------
// Feedback Event Types
// -----------------------------------------------------------------------------

/**
 * Feedback submitted event payload
 */
export interface FeedbackSubmittedEventPayload extends BaseEventPayload {
  /** Feedback ID */
  feedbackId: string;
  /** Order ID */
  orderId: string;
  /** Order number */
  orderNumber: string;
  /** Customer ID */
  customerId: string | null;
  /** Rating (1-5) */
  rating: number;
  /** Has comment */
  hasComment: boolean;
  /** Is public */
  isPublic: boolean;
}

// -----------------------------------------------------------------------------
// Order Module Events Map
// -----------------------------------------------------------------------------

/**
 * Order module domain events map
 */
export interface OrderModuleEvents {
  // Order lifecycle events
  'order.created': OrderCreatedEventPayload;
  'order.updated': OrderUpdatedEventPayload;
  'order.status_changed': OrderStatusChangedEventPayload;
  'order.confirmed': OrderConfirmedEventPayload;
  'order.preparing': OrderPreparingEventPayload;
  'order.ready': OrderReadyEventPayload;
  'order.delivered': OrderDeliveredEventPayload;
  'order.completed': OrderCompletedEventPayload;
  'order.cancelled': OrderCancelledEventPayload;

  // Order item events
  'order.item_added': OrderItemAddedEventPayload;
  'order.item_updated': OrderItemUpdatedEventPayload;
  'order.item_removed': OrderItemRemovedEventPayload;
  'order.item_status_changed': OrderItemStatusChangedEventPayload;

  // Table events
  'table.created': TableCreatedEventPayload;
  'table.updated': TableUpdatedEventPayload;
  'table.deleted': TableDeletedEventPayload;
  'table.status_changed': TableStatusChangedEventPayload;

  // Zone events
  'zone.created': ZoneCreatedEventPayload;
  'zone.updated': ZoneUpdatedEventPayload;
  'zone.deleted': ZoneDeletedEventPayload;

  // QR code events
  'qrcode.created': QRCodeCreatedEventPayload;
  'qrcode.scanned': QRCodeScannedEventPayload;
  'qrcode.deleted': QRCodeDeletedEventPayload;

  // Customer events
  'customer.created': CustomerCreatedEventPayload;
  'customer.updated': CustomerUpdatedEventPayload;

  // Service request events
  'service.requested': ServiceRequestedEventPayload;
  'service.resolved': ServiceResolvedEventPayload;

  // Feedback events
  'feedback.submitted': FeedbackSubmittedEventPayload;
}

/**
 * Order module event names
 */
export type OrderModuleEventName = keyof OrderModuleEvents;

/**
 * All order module event names as an array
 */
export const ORDER_MODULE_EVENTS: OrderModuleEventName[] = [
  // Order lifecycle events
  'order.created',
  'order.updated',
  'order.status_changed',
  'order.confirmed',
  'order.preparing',
  'order.ready',
  'order.delivered',
  'order.completed',
  'order.cancelled',

  // Order item events
  'order.item_added',
  'order.item_updated',
  'order.item_removed',
  'order.item_status_changed',

  // Table events
  'table.created',
  'table.updated',
  'table.deleted',
  'table.status_changed',

  // Zone events
  'zone.created',
  'zone.updated',
  'zone.deleted',

  // QR code events
  'qrcode.created',
  'qrcode.scanned',
  'qrcode.deleted',

  // Customer events
  'customer.created',
  'customer.updated',

  // Service request events
  'service.requested',
  'service.resolved',

  // Feedback events
  'feedback.submitted',
];

// -----------------------------------------------------------------------------
// Event Emitter Helpers
// -----------------------------------------------------------------------------

/**
 * Helper function to create timestamp
 */
function timestamp(): string {
  return new Date().toISOString();
}

/**
 * Emits an order created event
 */
export async function emitOrderCreated(
  eventService: EventService,
  payload: Omit<OrderCreatedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom('order.created', {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits an order updated event
 */
export async function emitOrderUpdated(
  eventService: EventService,
  payload: Omit<OrderUpdatedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom('order.updated', {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits an order status changed event
 */
export async function emitOrderStatusChanged(
  eventService: EventService,
  payload: Omit<OrderStatusChangedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom('order.status_changed', {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits an order confirmed event
 */
export async function emitOrderConfirmed(
  eventService: EventService,
  payload: Omit<OrderConfirmedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom('order.confirmed', {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits an order completed event
 */
export async function emitOrderCompleted(
  eventService: EventService,
  payload: Omit<OrderCompletedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom('order.completed', {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits an order cancelled event
 */
export async function emitOrderCancelled(
  eventService: EventService,
  payload: Omit<OrderCancelledEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom('order.cancelled', {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits an order item added event
 */
export async function emitOrderItemAdded(
  eventService: EventService,
  payload: Omit<OrderItemAddedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom('order.item_added', {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits a table created event
 */
export async function emitTableCreated(
  eventService: EventService,
  payload: Omit<TableCreatedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom('table.created', {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits a table status changed event
 */
export async function emitTableStatusChanged(
  eventService: EventService,
  payload: Omit<TableStatusChangedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom('table.status_changed', {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits a QR code scanned event
 */
export async function emitQRCodeScanned(
  eventService: EventService,
  payload: Omit<QRCodeScannedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom('qrcode.scanned', {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits a service requested event
 */
export async function emitServiceRequested(
  eventService: EventService,
  payload: Omit<ServiceRequestedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom('service.requested', {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits a feedback submitted event
 */
export async function emitFeedbackSubmitted(
  eventService: EventService,
  payload: Omit<FeedbackSubmittedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom('feedback.submitted', {
    ...payload,
    timestamp: timestamp(),
  });
}

// -----------------------------------------------------------------------------
// Export All Event Types
// -----------------------------------------------------------------------------

export type {
  BaseEventPayload,
  OrderCreatedEventPayload,
  OrderUpdatedEventPayload,
  OrderStatusChangedEventPayload,
  OrderConfirmedEventPayload,
  OrderPreparingEventPayload,
  OrderReadyEventPayload,
  OrderDeliveredEventPayload,
  OrderCompletedEventPayload,
  OrderCancelledEventPayload,
  OrderItemAddedEventPayload,
  OrderItemUpdatedEventPayload,
  OrderItemRemovedEventPayload,
  OrderItemStatusChangedEventPayload,
  TableCreatedEventPayload,
  TableUpdatedEventPayload,
  TableDeletedEventPayload,
  TableStatusChangedEventPayload,
  ZoneCreatedEventPayload,
  ZoneUpdatedEventPayload,
  ZoneDeletedEventPayload,
  QRCodeCreatedEventPayload,
  QRCodeScannedEventPayload,
  QRCodeDeletedEventPayload,
  CustomerCreatedEventPayload,
  CustomerUpdatedEventPayload,
  ServiceRequestedEventPayload,
  ServiceResolvedEventPayload,
  FeedbackSubmittedEventPayload,
};
